export interface SubModule {
  id: string;
  code: string;       // e.g. "1.1" or "OG1.1"
  title: string;
  blurb: string;
  kpis: { label: string; value: string; delta?: string; tone?: "success" | "warning" | "danger" | "info" }[];
  columns: string[];
  rows: (string | number)[][];
  chartType: "bar" | "line" | "area";
  chartLabel: string;
}

export interface Module {
  id: string;
  code: string;       // e.g. "M1" or "OGM1"
  title: string;
  short: string;
  purpose: string;
  wow: string;
  icon: LucideIcon;
  subModules: SubModule[];
}

export interface Sector {
  id: string;
  name: string;
  code: string;        // e.g. "MFG", "ONG"
  description: string;
  icon: LucideIcon;
  groups: {
    label: string;
    moduleIds: string[];
  }[];
  modules: Module[];
}

const months = ["Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar"];
const seriesA = months.map((m, i) => ({ name: m, value: 40 + ((i * 37) % 55) }));
const seriesB = months.map((m, i) => ({ name: m, value: 30 + ((i * 53) % 60) }));
export const demoSeries = { a: seriesA, b: seriesB };

// Compact helper for sub-modules so the file stays readable
const sub = (
  code: string, title: string, blurb: string,
  kpis: SubModule["kpis"], columns: string[], rows: SubModule["rows"],
  chartType: SubModule["chartType"] = "bar", chartLabel = "Last 30 days"
): SubModule => ({
  id: code.replace(".", "-"),
  code, title, blurb, kpis, columns, rows, chartType, chartLabel,
});

const k = (label: string, value: string, delta?: string, tone: SubModule["kpis"][number]["tone"] = "success") =>
  ({ label, value, delta, tone });

