export const modules: Module[] = sectors.flatMap(s => s.modules);

export const getModule = (id: string) => modules.find((m) => m.id === id);
export const getSubModule = (mid: string, sid: string) =>
  getModule(mid)?.subModules.find((s) => s.id === sid);
